    //- パラメータの合体
    function compileParameters(parameters, word1, word2) {
        let list = strToList(parameters[word1]);
        let i = 1;
        while (parameters[word2 + i]) {
            const addList = strToList(parameters[word2 + i]);
            list = [...list, ...addList];
            i++;
        }
        return list
    };
    
    
    
