    // 立ち絵の形成
    function createStand(scene, actor, noAnime, toDowner, forceAnime) {
        // 前の立ち絵を消去
        if (scene._standSpriteKeMnfs) {
            const preSprite = scene._standSpriteKeMnfs;
            preSprite.parent.removeChild(preSprite);
            preSprite.destroy();
            scene._standSpriteKeMnfs = null;
        }

        // 立ち絵データの取得
        const stand = getStandData(actor);
        if (!stand) { return; }
        if (stand["無効"]) { return; }

        // アニメを実行するか判定

        // アニメ強制なら実行
        if (forceAnime) {
            noAnime = false;
        // 開始アニメ無効なら実行しない
        } else　if (keke_standCfg["開始アニメ無効"]) {
            noAnime = true;
        // アクターの変更がなければ実行しない
        } else if (actor._actorId == $gameParty._standActorIdKeMnfs){
            noAnime = true;
        }

        // 立ち絵アクターのIDを保存
        $gameParty._standActorIdKeMnfs = actor._actorId;
        // 他キャラの立ち絵インデックスを初期化
        $gameParty.members().forEach(a => a != actor ? a._standIndexKeMnfs = null : 0);

        // ピクチャの形成
        const standSprite = createPicture(stand, scene, noAnime, forceAnime);
        if (!standSprite) { return; }
        // チルド
        if (toDowner || (stand["レイヤー"] && stand["レイヤー"].includes("下"))) {
            const windowLayerIndex = scene.children.indexOf(scene._windowLayer);
            scene.addChildAt(standSprite, windowLayerIndex);
        } else {
            scene.addChild(standSprite);
        }
        // 変数にセット
        scene._standSpriteKeMnfs = standSprite;
        // 拡張スプライト群のチルド
        childExtendSprites();
    };

    // 立ち絵の形成-パーティ
    function createStand_party(scene, noAnime, toDowner) {
        // 立ち絵を表示するアクターを取得する

        let actor = null;
        // 前の立ち絵アクターを取得
        let preActor = null;
        if ($gameParty._standActorIdKeMnfs) {
            preActor = $gameParty.members().find(actor => $gameParty._standActorIdKeMnfs == actor._actorId);
        }
        if (preActor) { actor = preActor; }
        // 取得できなければランダムで取得
        if (!actor) {
            // ランダム立ち絵タイプに応じてメンバー配列を取得
            const randomType = keke_standCfg["ランダム立ち絵タイプ"];
            let members = [];
            if (randomType == "パーティ全体からランダム") {
                members = $gameParty.allMembers();
            } else if (randomType == "先頭メンバー固定") {
                members = [$gameParty.members()[0]];
            } else {
                members = $gameParty.allBattleMembers();
            }
            // 立ち絵データのあるメンバーを取得
            standMembers = members.filter(actor => getStandData(actor));
            if (!standMembers.length) { return; }
            // ランダムで立ち絵を表示するメンバーを取得
            actor = standMembers[Math.randomInt(standMembers.length)];
        }

        // メニュー開始直後かを取得
        const isMenuStarting = SceneManager._previousScene.constructor.name.match(/Scene_Map|Scene_Battle/i);
        // メニュー開始直後の場合の処理
        let forceAnime = false;
        if (isMenuStarting) {
            // 立ち絵アニメを強制実行
            forceAnime = true;
            // 立ち絵アクターのIDを保存
            //$gameParty._standActorIdKeMnfs = actor._actorId;
        }

        // 立ち絵の形成
        createStand(scene, actor, noAnime, toDowner, forceAnime);
    };



