    //==================================================
    //--  ピクチャ
    //==================================================
    
    //- ピクチャの形成
    function createPicture(pict, scene, noAnime) {
        if (!pict) { return; }
        // ビットマップ形成
        const bitmap = getCharaImage(pict["キャラデータ名"], pict["└画像名"]) || ImageManager.loadPicture(pict["画像"]);
        if (!bitmap) { return { sprite:null }; }
        // スプライト形成
        const sprite = new SpriteKeMnfs(bitmap);
        // 原点
        sprite.anchor.x = pict["原点X"]　!= null ? pict["原点X"] : 0.5;
        sprite.anchor.y = pict["原点Y"] != null ? pict["原点Y"] : 1;
        // スケール
        sprite._scaleXKe = (pict["スケールX"] || 1) * (pict["スケール"] || 1);
        sprite._scaleYKe = (pict["スケールY"] || 1) * (pict["スケール"] || 1);
        // 固定幅
        if (pict["横幅"]) { sprite._fixWKe = newFunc_screenW(pict["横幅"]) || 0; }
        sprite._fixHKe = newFunc_screenW(pict["高さ"] || "gh") || 0;
        // 回転角
        sprite._angleKe = pict["回転角"] || 0;
        sprite.rotation = angleToRadian(sprite._angleKe);
        // 不透明度
        sprite.opacity = pict["不透明度"] || 255;
        // カラートーン
        const colorTone = strToColorTone(pict);
        if (colorTone) { sprite.setColorTone(colorTone); }
        // ビットマップ読み込み待ち
        bitmap.addLoadListener(() => {
            // ピクチャの仕上げ
            finishPicture(sprite, scene, pict, noAnime);
        });
        return sprite
    };

    //- ピクチャの仕上げ
    function finishPicture(sprite, scene, pict, noAnime) {
        if (!sprite.transform) { sprite._breakSetupKe = true;  return; }
        // 画像を固定幅に合わせる
        adjustImageToFixedWidth(sprite);
        // サイズを保存
        sprite._widthKe = sprite.width * Math.abs(sprite.scale.x);
        sprite._heightKe = sprite.height * Math.abs(sprite.scale.y);
        // 原点による位置補正
        const anchoredX = sprite._widthKe * (sprite.anchor.x - 0.5);
        const anchoredY = sprite._heightKe * (sprite.anchor.y - 0.5);
        // 位置
        sprite._offsetXKe = calcMulti(0, pict["位置X"], null, { sw:sprite._widthKe, sh:sprite._heightKe })[0].val + anchoredX;
        sprite._offsetYKe = calcMulti(0, pict["位置Y"], null, { sw:sprite._widthKe, sh:sprite._heightKe })[0].val + anchoredY;
        sprite.x = sprite._offsetXKe;
        sprite.y = sprite._offsetYKe ;
        // 画像の位置揃え
        alignImagePos(sprite, pict);
        // スプライトの標準値を保存
        saveSpriteOriVal(sprite);
        // アニメタイプを取得
            const animeType = "_stand";
        if (!noAnime) {
            // アニメの呼び出し-開く
            callAnime(sprite, scene, pict["開始アニメ"] || keke_standCfg["開始アニメ共通"], "start" + animeType, pict["アニメディレイ"]);
        }
        // アニメの呼び出し-表示中
        callAnime(sprite, scene, pict["表示中アニメ"], "ing" + animeType, pict["アニメディレイ"]);
        // セットアップ完了フラグ
        sprite._isSetupedKe = true;
    }

    //- 画像を固定幅に合わせる
    function adjustImageToFixedWidth(sprite) {
        if (sprite._fixWKe) {
            sprite.scale.x = sprite._fixWKe / sprite.width * sprite._scaleXKe;
        } else if (sprite._fixHKe) {
            sprite.scale.x = sprite._fixHKe / sprite.height * sprite._scaleXKe;
        }
        if (sprite._fixHKe) {
            sprite.scale.y = sprite._fixHKe / sprite.height * sprite._scaleYKe;
        } else if (sprite._fixWKe) {
            sprite.scale.y = sprite._fixWKe / sprite.width * sprite._scaleYKe;
        }
    };

    //- 画像の位置揃え
    function alignImagePos(sprite, pict) {
        // 位置寄せ
        alignX = pict["位置寄せX"];
        alignY = pict["位置寄せY"];
        // 位置揃えX
        if (alignX) {
            if (alignX.includes("左")) {
                sprite.x = sprite._widthKe / 2;
            } else if (alignX.includes("右")) {
                sprite.x = Graphics.width - sprite._widthKe / 2;
            } else {
                sprite.x = Graphics.width / 2;
            }
            sprite.x += sprite._offsetXKe;
        }
        // 位置揃えY
        if (alignY) {
            if (alignY.includes("上")) {
                sprite.y = sprite._heightKe / 2;
            } else if (alignY.includes("下")) {
                sprite.y = Graphics.height - sprite._heightKe / 2;
            } else {
                sprite.y = Graphics.height / 2;
            }
            sprite.y += sprite._offsetYKe;
        }
    };
    
    //- スプライトの標準値を保存
    function saveSpriteOriVal(sprite) {
        sprite._posXOriKe = sprite.x;
        sprite._posYOriKe = sprite.y;
        sprite._scaleXOriKe = "*" + sprite.scale.x;
        sprite._scaleYOriKe = "*" + sprite.scale.y;
        sprite._angleOriKe = sprite._angleKe || 0;
        sprite._opacityOriKe = "*" + sprite.opacity / 255;
        sprite._colorToneOriKe = sprite._colorTone.concat();
    };



